INSERT INTO `ai_config` VALUES (1, 'default', 'AI 助手', NULL, '你好！我是 **{botName}**，可以帮你写作、翻译、编程、分析等各类问题，有什么我可以帮你的吗？', '你是一个智能 AI 助手，能够进行自然、流畅的多轮对话。\n你可以帮助用户完成写作、翻译、编程、分析、头脑风暴、学习辅导等广泛任务。\n请根据用户问题选择合适的方式回答：简洁问题简洁答，复杂问题条理清晰。\n使用 Markdown 格式化代码、列表和重点内容；不确定时请诚实说明，不要编造。', 'deepseek-chat', 0.70, 30, '[{\"id\":\"deepseek-chat\",\"label\":\"DeepSeek Chat\"},{\"id\":\"deepseek-reasoner\",\"label\":\"DeepSeek Reasoner\"}]', '0', 5, '0', '0', '系统默认 AI 配置', 'admin', '2026-07-06 10:24:17', 'admin', '2026-07-06 16:27:07');
