INSERT INTO `ai_knowledge_chunk` VALUES (3, 4, 1, 0, '# StarPivot 常见问题 FAQ\n\n## 登录与账号\n\n问：忘记密码怎么办？\n答：请联系系统管理员在「系统管理 → 用户管理」中重置密码。若环境已对接自助找回流程，可在登录页使用忘记密码功能（以实际部署为准）。\n\n问：登录后左侧菜单很少，很多功能看不到？\n答：这是权限未分配导致。请管理员进入「系统管理 → 角色管理」，编辑你的角色，勾选需要的菜单和按钮权限后保存，然后退出重新登录。\n\n问：提示无权限或 403？\n答：说明当前账号缺少该功能的按钮权限（如 ai:knowledge:edit）。需管理员在角色管理中补充对应权限标识。\n\n问：登录后很快掉线？\n答：Token 可能过期或被踢下线。可在「系统监控 → 在线用户」查看会话；重新登录即可。若频繁掉线，联系管理员检查 Redis 与 JWT 配置。\n\n## 用户与权限管理\n\n问：如何新增一个后台用户？\n答：进入「系统管理 → 用户管理」，点击新增，填写用户名、昵称、部门、岗位，分配角色后保存。\n\n问：如何给用户开通 AI 知识库管理权限？\n答：在「系统管理 → 角色管理」中，为角色勾选「AI 中心」及其子菜单（基础配置、知识库、会话管理等），并勾选对应按钮权限（如 ai:knowledge:edit）。', '[-0.036685388535261154, -0.0326857827603817, -0.06678768992424011, -0.0027724546380341053, -0.0670938789844513, -0.03655143082141876, 0.0767771378159523, 0.014553593471646307, 0.016228070482611656, -0.03130792826414108, 0.045316118746995926, -0.008558967150747776, -0.03136533871293068, 0.0285713542252779, 0.036015596240758896, -0.0457754023373127, 0.050215158611536026, 0.05764026567339897, -0.01020952221006155, -0.011472556740045547, -0.03463774174451828, -0.0010363813489675522, -0.0038369433023035526, 0.03815892711281776, 0.038809582591056824, 0.07053852081298828, -0.020954877138137817, -0.04187148064374924, 0.06896929442882538, -0.03465687856078148, 0.034542057663202286, -0.08358986675739288, -0.018581904470920563, -0.04799528047442436, -0.018361831083893776, -0.026504570618271828, 0.007760002743452787, 0.015290362760424614, -0.07700678706169128, 0.014266540296375751, -0.027231773361563683, -0.038790445774793625, 0.009314874187111856, -0.03513530269265175, -0.005387030076235533, -0.03565199673175812, 0.02284942753612995, 0.0012438968988135457, 0.02811206877231598, -0.012123210355639458, -0.007750434335321188, 0.01493633072823286, 0.026561981067061424, -0.08358986675739288, 0.018562767654657364, 0.03287715092301369, 0.007917881943285465, -0.02793983742594719, -0.005592751782387495, 0.020878329873085025, -0.04914349317550659, 0.006740964017808437, -0.03010230