INSERT INTO `ai_knowledge_chunk` VALUES (4, 4, 1, 1, '统管理 → 角色管理」中，为角色勾选「AI 中心」及其子菜单（基础配置、知识库、会话管理等），并勾选对应按钮权限（如 ai:knowledge:edit）。\n\n问：超级管理员和普通管理员有什么区别？\n答：超级管理员通常拥有全部菜单权限；普通角色仅拥有被分配的菜单与按钮权限，遵循最小权限原则。\n\n## 审批中心\n\n问：如何发起审批？\n答：进入「审批中心」，选择对应业务类型的审批模板或入口，填写表单后提交。可在「我发起的」查看进度。\n\n问：审批被驳回了怎么办？\n答：在「我发起的」或待办列表中打开该单据，查看驳回意见，修改内容后重新提交。\n\n问：收不到审批通知？\n答：检查「系统管理 → 消息中心」是否有站内消息；确认审批服务与消息服务正常运行，必要时重新登录刷新消息连接。\n\n## 商城相关\n\n问：商品上架后 C 端看不到？\n答：检查商品审核/上架状态、库存是否充足，以及 C 端商城入口是否正常。B 端在「商城系统 → 商品管理」维护。\n\n问：订单支付失败？\n答：开发环境可能使用支付沙箱，检查支付配置与订单状态；生产环境联系运维确认支付渠道配置。\n\n## 文件中心\n\n问：上传文件失败？\n答：检查文件大小是否超限、当前用户是否有 file:resource 相关权限，以及文件服务（starpivot-file）与 OSS/存储配置是否正常。\n\n## AI 助手与知识库', '[-0.0595259852707386, -0.049772050231695175, -0.036818210035562515, -0.006563665345311165, -0.035468850284814835, -0.035160426050424576, 0.03344481438398361, 0.03093886189162731, 0.0017071794718503952, 0.003980607260018587, 0.03753144294023514, -0.01975846290588379, 0.007199791260063648, 0.06318853050470352, 0.013185160234570503, -0.005595018621534109, 0.03756999596953392, 0.006872090045362711, -0.014447773806750774, -0.014997155405580996, -0.07363642007112503, 0.0019637984223663807, -0.02243790403008461, 0.0219174362719059, 0.054244209080934525, 0.057752542197704315, -0.06361261010169983, -0.0577910952270031, 0.047458864748477936, -0.0013071909779682755, 0.005619114264845848, -0.0963827446103096, -0.004269755911082029, -0.04549265652894974, 0.012587586417794228, -0.025560704991221428, -0.0143899442628026, -0.01676096022129059, -0.08119282871484756, 0.01692480966448784, -0.02313186042010784, -0.01861150935292244, 0.019565697759389877, -0.04641793295741081, 0.001603567972779274, -0.010428613051772118, 0.026505256071686745, -0.04738175868988037, -0.003496284130960703, 0.02228369191288948, -0.047458864748477936, -0.004734802525490522, 0.0012041819281876087, -0.0209343321621418, 0.02544504590332508, 0.09676828235387802, 0.04472159594297409, -0.005542008206248283, 0.003233641153201461, 0.07417616248130798, -0