INSERT INTO `ai_knowledge_chunk` VALUES (5, 4, 1, 2, '当前用户是否有 file:resource 相关权限，以及文件服务（starpivot-file）与 OSS/存储配置是否正常。\n\n## AI 助手与知识库\n\n问：AI 助手在哪里打开？\n答：登录管理端后，点击页面右下角的 AI 对话图标即可打开聊天窗口。\n\n问：AI 能回答公司内部产品问题吗？\n答：可以，需同时满足：① Nacos 中 RAG 已开启；②「AI 中心 → 基础配置」中启用 RAG；③ 知识库中已上传文档且索引状态为「已完成」。否则 AI 仅按通用知识回答。\n\n问：如何在知识库添加文档？\n答：进入「AI 中心 → 知识库」，选择知识库后进入文档管理，可「上传文件」（支持 PDF、DOCX、MD、TXT）或「粘贴文本」。保存后等待索引完成。\n\n问：知识库文档索引一直失败？\n答：常见原因：Embedding API 未配置或地址错误（DashScope 的 base-url 不要带 /v1）、文档为纯图片 PDF 无法解析。可在文档列表点击「重建索引」，并查看后台 IndexService 日志。\n\n问：AI 回答没有引用知识库内容？\n答：确认提问用语与文档内容相关；检查日志是否有 vectorHits > 0；知识库文档是否索引完成且 RAG 双开关均已开启。', '[-0.05281619355082512, -0.033661991357803345, -0.01650751195847988, -0.004276366904377937, -0.048424649983644485, -0.04591519385576248, 0.025251396000385284, 0.04536624997854233, -0.034485407173633575, 0.0018048963975161312, 0.021036295220255852, -0.029995834454894062, 0.0256631039083004, 0.03515198081731796, 0.043248895555734634, -0.007797936908900738, -0.014890089631080627, 0.002062213607132435, -0.01995801366865635, -0.03166227042675018, -0.03340712562203407, 0.029858598485589027, 0.04426836222410202, 0.025212185457348824, 0.08273360878229141, 0.06904923170804977, -0.03905339911580086, -0.03395606949925423, 0.08924251049757004, -0.05591380596160889, 0.0067490627989172935, -0.07689128071069717, 0.004957644734531641, -0.00882230419665575, 0.013841215521097183, -0.03828880190849304, -0.005886437371373177, -0.02601599507033825, -0.07155869156122208, 0.016125211492180824, -0.04571914300322533, -0.0176446083933115, 0.030819250270724297, -0.05732537433505058, -0.033446334302425385, -0.008557635359466076, -0.005695287603884935, -0.018164144828915596, 0.02327127754688263, 0.01329227164387703, -0.021291160956025124, -0.02095787413418293, 0.013409902341663836, -0.03360317647457123, 0.012978590093553066, 0.03381883352994919, -0.006146205123513937, -0.020046235993504524, -0.07238210737705231, 0.0039969938807189465, -0.05414934456348419, -0.03805353865027428, -0.051639