INSERT INTO `ai_knowledge_chunk` VALUES (6, 4, 1, 3, '回答没有引用知识库内容？\n答：确认提问用语与文档内容相关；检查日志是否有 vectorHits > 0；知识库文档是否索引完成且 RAG 双开关均已开启。\n\n问：AI 对话可以选择不同场景吗？\n答：可以。系统支持多种提示词场景（如通用助手、客服问答、开发辅助、数据分析），在对话窗口切换场景后，回答风格会相应调整。\n\n## 系统运维（开发环境参考）\n\n问：服务启动后接口 502 或连不上？\n答：检查网关（8080）、对应微服务是否已注册到 Nacos（8848），以及 MySQL（3307）、Redis（6379）是否已启动。常用命令：docker compose up -d 启动中间件。\n\n问：修改 Nacos 配置后不生效？\n答：部分配置支持热刷新，AI Embedding 等客户端通常需重启对应微服务（如 starpivot-ai）后生效。\n\n问：数据库脚本在哪里？\n答：项目 sql/ 目录，核心库为 star_pivot；商城等业务有独立分库脚本，详见项目 README。', '[-0.02435864508152008, -0.028007665649056435, -0.0468832291662693, 0.024855369701981544, -0.0730186179280281, -0.04822056367993355, 0.06186140701174736, 0.04833519458770752, -0.02804587595164776, 0.018713170662522316, 0.004649635404348373, -0.007384012918919325, 0.029956357553601265, 0.02418670244514942, 0.020327528938651085, -0.025428514927625656, 0.011252738535404204, 0.020957987755537033, 0.03840068727731705, -0.030796969309449196, -0.040616847574710846, 0.013908308930695055, 0.043941084295511246, 0.03916488215327263, 0.04520200192928314, 0.08260924369096756, -0.08207430690526962, -0.06006555259227753, 0.09483632445335388, -0.011052138172090054, -0.0030018447432667017, -0.06178498640656471, 0.002317653503268957, -0.03702514246106148, 0.010507650673389437, -0.03799948841333389, 0.006443100515753031, 0.01059362292289734, -0.0918559730052948, 0.03469435125589371, -0.017146576195955276, -0.02915395423769951, 0.023861920461058617, -0.003734992351382971, 0.035038240253925323, -0.04034937918186188, -0.012609180994331837, -0.03738813102245331, 0.009848535060882568, 0.0009880773723125458, -0.05731445923447609, -0.018904218450188637, 0.006720120552927256, -0.041915975511074066, 0.0027009439654648304, 0.002162426710128784, -0.01735672913491726, -0.05001641809940338, -0.05972166731953621, 0.04974894970655441, -0.060791537165641785, 0.033930160105228424, 0.02074783481657505, -0.001317038550041616, -0.015494008548557758, 0.05593891069293022, -0.02989904209971428, 0.000