INSERT INTO `ai_knowledge_chunk` VALUES (7, 5, 1, 0, '# StarPivot 星枢后台管理系统 — 产品概览\n\nStarPivot（星枢）是一套企业级微服务管理平台，采用前后端分离架构，管理端为 Vue 3 + Element Plus，API 统一前缀为 /api/v1，默认通过网关端口 8080 访问。\n\n## 主要功能模块\n\n### 系统管理\n路径：左侧菜单「系统管理」\n包含：菜单管理、角色管理、用户管理、部门管理、岗位管理、字典管理、日志管理（操作日志/登录日志）、通知公告、参数配置、消息中心。\n用途：维护组织架构、账号权限、系统参数与站内消息。\n\n### 系统工具\n路径：「系统工具」\n包含：代码生成、外部库代码生成。\n用途：根据数据库表快速生成前后端代码。\n\n### 系统监控\n路径：「系统监控」\n包含：服务器监控、Druid 监控、Redis 缓存、在线用户、定时任务。\n用途：查看运行状态、连接池、缓存与调度任务。\n\n### 文件中心\n路径：「文件中心 → 文件管理」\n用途：统一上传、分类管理与下载业务文件。\n\n### 商城系统\n路径：「商城系统」\n包含：C 端商城、商品管理、仓库系统、订单系统、优惠营销等子模块。\n用途：B 端商品/库存/订单/营销管理，以及 C 端购物前台。\n\n### 审批中心\n路径：「审批中心」\n用途：配置审批模板、发起与处理审批单、查看审批进度与通知。', '[-0.08026143163442612, -0.008623048663139343, -0.08220575004816055, 0.01214226335287094, -0.042813874781131744, -0.047674667090177536, 0.008083500899374485, 0.0442526675760746, 0.0018215825548395512, 0.03505604714155197, 0.003008831525221467, 0.01518512051552534, 0.019307073205709457, 0.010596531443297865, -0.0003697241481859237, -0.042075034230947495, 0.05576302856206894, 0.010722911916673183, 0.05008562281727791, -0.01634198985993862, -0.05024116858839989, -0.008141829632222652, 0.008404312655329704, 0.08663879334926605, 0.024206753820180893, 0.03206179663538933, -0.021445823833346367, -0.019725102931261063, 0.04942455515265465, 0.008268211036920547, 0.015642035752534866, -0.09013856202363968, 0.0008239045855589211, -0.011296485550701618, -0.00817099492996931, -0.05700739473104477, 0.01298804208636284, 0.003562962170690298, -0.10600419342517851, 0.007252304814755917, -0.04024737328290939, -0.04238612577319145, 0.0025251824408769608, -0.008102944120764732, -0.0040417504496872425, -0.038691919296979904, 0.019666772335767743, -0.029884161427617073, -0.08205020427703857, -0.014426836743950844, -0.04751912131905556, 0.006882884539663792, -0.009974349290132524, -0.07497289031744003, 0.0329950712621212, 0.014553217217326164, -0.03289785608649254, -0.04662473499774933, -0.01147147361189127, 0.06618457287549973, -0.05035