INSERT INTO `ai_knowledge_chunk` VALUES (8, 5, 1, 1, 'B 端商品/库存/订单/营销管理，以及 C 端购物前台。\n\n### 审批中心\n路径：「审批中心」\n用途：配置审批模板、发起与处理审批单、查看审批进度与通知。\n\n### 物流管理（TMS）\n路径：「物流管理」\n包含：承运商配置、运单管理、运费规则。\n用途：维护承运商、创建运单、查询物流轨迹与运费。\n\n### AI 中心\n路径：「AI 中心」\n包含：基础配置、会话管理、知识库、用量统计。\n用途：配置 AI 助手、管理对话会话、维护 RAG 知识库文档、查看 AI 调用统计。\n用户可在页面右下角打开 AI 对话窗口进行智能问答。\n\n## 默认登录信息（开发环境）\n默认管理员账号：admin\n默认密码：admin123（若已修改请使用实际密码）\n登录地址：管理前端开发地址一般为 http://localhost:3000\n\n## 权限说明\n用户能看到的菜单由「角色」分配的菜单权限决定。若登录后菜单很少或某功能按钮灰色不可用，需联系管理员在「系统管理 → 角色管理」中为该角色勾选对应菜单与按钮权限。', '[-0.029962388798594475, -0.05344853177666664, -0.07510104030370712, 0.018463151529431343, -0.054931048303842545, -0.06097814440727234, 0.010436118580400944, 0.009860669262707232, 0.0019031286938115952, 0.04041801393032074, 0.00685662729665637, 0.04236869141459465, -0.005457017105072737, 0.025553859770298004, 0.0005906891892664135, -0.022296231240034103, 0.033961277455091476, 0.018511919304728508, 0.01112860906869173, -0.04221263527870178, -0.04287586733698845, 0.0077344318851828575, -0.029299158602952957, 0.032927416265010834, 0.040183935314416885, 0.022335244342684742, -0.05543822422623634, -0.049469154328107834, 0.06327994167804718, -0.02036506123840809, 0.010124010033905506, -0.060041818767786026, -0.03189355880022049, -0.015819985419511795, 0.00480597885325551, -0.02898705191910267, -0.02015048637986183, -0.008397662080824375, -0.1113446056842804, 0.017517073079943657, -0.028245793655514717, -0.001726348651573062, 0.0013057340402156117, -0.016297901049256325, 0.002440783893689513, -0.03899402171373367, 0.024305427446961403, -0.04002787917852402, -0.025612380355596542, -0.0238177590072155, -0.05009337142109871, -0.01640518754720688, -0.0022213326301425695, -0.05274628847837448, 0.05875437334179878, 0.07650552690029144, -0.02487112395465374, -0.04330501705408096, -0.002562701003625989, 0.04888394847512245, -0.04775255918502808, -0.010358091443777084, 0.023427624255418777, 0.032712843269109726, -0.0072077494114637375, 0.001838512485846877, 0.0