INSERT INTO `ai_knowledge_chunk` VALUES (9, 6, 3, 0, '# StarPivot 审批中心操作手册\n\n审批中心是 StarPivot 的统一审批中台，可与商城采购、退货、优惠券、商品上架等业务联动。菜单路径：左侧「审批中心」。\n\n## 审批中心子菜单\n\n| 菜单 | 路径 | 用途 |\n|------|------|------|\n| 审批模板 | 审批中心 → 审批模板 | 配置审批流程步骤、审批人策略、超时规则 |\n| 业务绑定 | 审批中心 → 业务绑定 | 将业务类型（如采购单）绑定到具体审批模板 |\n| 待办审批 | 审批中心 → 待办审批 | 处理分配给自己的待办，进行通过或驳回 |\n| 我发起的 | 审批中心 → 我发起的 | 查看自己提交的审批进度，可撤回进行中的审批 |\n| 审批统计 | 审批中心 → 审批统计 | 查看审批数据看板与统计 |\n\n## 审批状态说明\n\n### 审批实例状态\n- 审批中：流程正在进行，有待办未处理\n- 已通过：所有审批节点均已通过\n- 已驳回：某一节点审批人驳回，流程结束\n- 已撤回：发起人主动撤回，流程结束\n\n### 业务单 audit_status（以商城为例）\n- DRAFT：草稿，可编辑，可提交审批\n- PENDING：审批中，一般不可直接执行业务后续操作\n- APPROVED：审批已通过，可继续入库、上架、发布等\n- REJECTED：已驳回，需修改后重新提交', '[-0.07300027459859848, -0.04327217862010002, -0.06779690086841583, 0.01133455615490675, -0.02756640501320362, -0.03076112270355225, 0.02001003362238407, 0.061904847621917725, 0.005251199472695589, 0.0360792763531208, 0.02814030647277832, 0.03181327506899834, 0.016710100695490837, 0.05279894173145294, 0.010005016811192036, -0.0383748859167099, 0.060642264783382416, 0.0093019874766469, 0.035964496433734894, -0.005356414709240198, -0.08776868134737015, -0.0069346437230706215, 0.0174370426684618, 0.016796184703707695, 0.02393169514834881, 0.0372462123632431, -0.029230719432234764, -0.0191778764128685, 0.0406704917550087, -0.026456862688064575, 0.018690060824155807, -0.09014080464839937, -0.01389798242598772, -0.03810706362128258, 0.027375103905797005, -0.06247875094413757, -0.0011687265941873193, -0.0007113987812772393, -0.06925078481435776, 0.014232758432626724, -0.051574621349573135, -0.026246430352330208, 0.019321352243423465, -0.02768118493258953, -0.005227286834269762, -0.03799228370189667, 0.026590771973133087, -0.04740426689386368, -0.044840842485427856, 0.01410841289907694, -0.032387178391218185, 0.010205882601439953, 0.012807569466531277, -0.07062815129756927, 0.029823750257492065, 0.06010662391781807, -0.000736507005058229, -0.033534981310367584, 0.002785813761875034, 0.03801141306757927, -0.01707357