INSERT INTO `ai_knowledge_chunk` VALUES (10, 6, 3, 1, 'ENDING：审批中，一般不可直接执行业务后续操作\n- APPROVED：审批已通过，可继续入库、上架、发布等\n- REJECTED：已驳回，需修改后重新提交\n- WITHDRAWN：已撤回，可修改后再次提交\n\n## 管理员：配置审批流程\n\n### 第一步：创建审批模板\n1. 进入「审批中心 → 审批模板」\n2. 点击新增，填写模板名称、编码、说明\n3. 配置审批步骤（可多级），每步指定审批人策略：\n   - DEPT_LEADER：发起人部门负责人\n   - ROLE：指定角色（如 finance 财务角色）\n   - USER：指定具体用户\n4. 保存后点击「发布」，只有已发布模板可被业务使用\n\n### 第二步：业务类型绑定\n1. 进入「审批中心 → 业务绑定」\n2. 为业务类型（如 purchase 采购单、return 退货单、coupon 优惠券、spu 商品）选择对应已发布模板\n3. 保存绑定关系\n\n### 角色与权限\n审批人需具备对应角色。例如默认采购单模板为「部门负责人 → 财务」两关：\n- 第一关：发起人所在部门负责人\n- 第二关：拥有 finance 角色的用户\n在「系统管理 → 角色管理」中为用户分配 finance 等角色后，需重新登录生效。\n\n## 业务用户：发起审批（以采购单为例）', '[-0.07485191524028778, -0.029627270996570587, -0.017251934856176376, 0.025369923561811447, -0.04183812066912651, 0.01182381622493267, 0.04729526489973068, 0.05089465901255608, -0.007014948409050703, 0.018945198506116867, 0.028369419276714325, 0.06204117089509964, 0.02931764535605907, 0.06238949671387672, -0.006492455489933491, -0.012675286270678043, 0.045398809015750885, -0.030323928222060204, 0.030169116333127025, 0.019622502848505977, -0.04636638984084129, -0.030246522277593613, 0.04365716874599457, 0.009719331748783588, 0.022989679127931595, 0.011736733838915823, -0.05027540773153305, -0.01765831746160984, 0.04458604380488396, -0.03727114573121071, -0.004891111981123686, -0.05128169059753418, -0.04044480621814728, -0.045514918863773346, 0.0492304228246212, -0.04613417014479637, 0.0010328906355425715, -0.00402996689081192, -0.0707106813788414, -0.016255328431725502, -0.0246152114123106, 0.004574229940772057, 0.007319735828787088, -0.04578584060072899, 0.03183335065841675, 0.004092859569936991, -0.014300818555057049, -0.04203163459897041, -0.017842158675193787, 0.0012082643806934357, -0.04737267270684242, 0.01394281443208456, 0.003836451098322868, -0.05035281553864479, 0.03442646190524101, 0.0897139310836792, -0.005113655235618353, -0.024324938654899597, -0.033574994653463364, 0.05015929788351059, -0.030420685186982155, 0.031601