INSERT INTO `ai_knowledge_chunk` VALUES (14, 7, 3, 0, '# StarPivot AI 中心管理员指南\n\nAI 中心用于配置智能对话助手、管理知识库（RAG）、查看会话与用量。菜单路径：左侧「AI 中心」。普通用户通过页面右下角 AI 图标打开对话窗口。\n\n## AI 中心子菜单\n\n| 菜单 | 用途 |\n|------|------|\n| 基础配置 | 助手名称、欢迎语、系统提示词、模型、RAG 开关等 |\n| 会话管理 | 管理员查看与删除用户对话会话 |\n| 知识库 | 维护 RAG 文档，上传产品手册、FAQ 等 |\n| 用量统计 | 查看 AI 调用次数、Token 消耗、耗时等 |\n\n## 开启 RAG 知识库问答（必做两步）\n\nRAG 需要同时满足两个开关，缺一不可：\n\n### 开关一：Nacos 基础设施（运维配置）\n在 Nacos 的 starpivot-ai.yaml 中设置：\n- starpivot.ai.rag.enabled: true\n- spring.ai.openai.embedding 配置 DashScope 等 Embedding API\n- embedding 的 base-url 不要带 /v1（Spring AI 会自动追加）\n\n修改后需重启 starpivot-ai 服务。', '[-0.03185353800654411, -0.02810833416879177, -0.061081573367118835, -0.0010871227132156491, -0.07725930958986282, -0.04312776029109955, 0.02515464276075363, 0.020405570045113564, -0.007268398534506559, 0.03083036467432976, -0.0033325557596981525, -0.007697938475757837, -0.006544454488903284, 0.046139366924762726, 0.04278026893734932, -0.03832077234983444, 0.03768370300531387, 0.037027325481176376, 0.04494244605302811, -0.02260635979473591, -0.05563751608133316, 0.014198956079781055, -0.015569623559713364, 0.018281999975442886, 0.0409269705414772, 0.05911244451999664, -0.05822440981864929, -0.04034781455993652, 0.08617830276489258, -0.0293438658118248, -0.014256872236728668, -0.0938231498003006, -0.023571617901325222, -0.003030912484973669, 0.015251087956130505, -0.024498267099261284, -0.00710913073271513, -0.012683499604463576, -0.10502015054225922, 0.007726896554231644, -0.04397718980908394, -0.03874548524618149, 0.017326394096016884, -0.008682502433657646, 0.01787659153342247, -0.023957721889019012, -0.004432950634509325, -0.040849748998880386, 0.006332097575068474, 0.02227817289531231, -0.05003901198506355, -0.020154602825641632, -0.00506278220564127, -0.01992294006049633, 0.032085202634334564, 0.043513864278793335, -0.012635237537324429, -0.03673774749040603, -0.014720195904374124, 0.021467354148626328, -0.07343688607215881, -0.020868893712759014, -0.00