INSERT INTO `ai_knowledge_chunk` VALUES (15, 7, 3, 1, 'g API\n- embedding 的 base-url 不要带 /v1（Spring AI 会自动追加）\n\n修改后需重启 starpivot-ai 服务。\n\n### 开关二：后台业务开关\n1. 进入「AI 中心 → 基础配置」\n2. 编辑默认配置（或新建并设为默认）\n3. 在「RAG 知识库」区域打开「启用 RAG」\n4. 设置「检索条数」（建议 3～10，默认 5）\n5. 保存\n\n## 基础配置项说明\n\n| 配置项 | 说明 |\n|--------|------|\n| 配置名称 | 如 default，用于区分多套配置 |\n| 助手名称 | 对话窗口显示的名称，支持欢迎语 {botName} 占位符 |\n| 助手头像 | 完整图片 URL，留空用默认头像 |\n| 欢迎语 | 打开新会话时展示的首条消息 |\n| 系统提示词 | 定义 AI 行为边界与回答风格 |\n| 默认模型 | 如 deepseek-chat，需与 Nacos 中配置的模型一致 |\n| 默认温度 | 0～2，越低越稳定，越高越有创造性 |\n| 记忆条数 | 每个会话保留的历史消息条数，默认 30 |\n| 启用 RAG | 是否在本配置下启用知识库检索 |\n| 检索条数 | 每次对话从知识库检索的片段数量 |\n| 设为默认 | 同时只能有一套默认配置生效 |\n\n## 对话场景（提示词模板）', '[-0.04444744810461998, -0.03205757588148117, -0.047179073095321655, 0.01634097471833229, -0.06349077820777893, -0.07051496207714081, 0.0695393830537796, 0.017775077372789383, -0.036447688937187195, 0.007672940846532583, -0.009443619288504124, 0.02612604759633541, 0.020253051072359085, 0.026535790413618088, 0.02645774371922016, -0.04448647052049637, 0.051549676805734634, 0.028428416699171063, 0.02755039371550083, -0.01770678721368313, -0.03728668764233589, 0.0187994372099638, -0.013463011011481283, -0.012692302465438845, 0.05670074000954628, 0.06064208596944809, -0.0768367201089859, -0.03599892184138298, 0.058105576783418655, -0.010438711382448672, -0.0054778847843408585, -0.03878908231854439, 0.00021203633514232936, -0.043471869081258774, 0.007916836068034172, -0.017892146483063698, -0.020545726642012596, 0.002129204571247101, -0.11582092195749284, 0.003987685311585665, -0.029423508793115616, -0.020194517448544506, 0.015921473503112793, -0.014360545203089714, 0.0139117781072855, -0.03707205876708031, 0.005814460106194019, -0.05006679147481918, 0.03793057054281235, 0.0033023401629179716, -0.04292554408311844, -0.000337794772349298, -0.0038803715724498034, -0.015394660644233229, 0.03262341395020485, 0.030945414677262303, -0.015443439595401289, 0.018340913578867912, -0.04097438231110573, -0.0091802123934030