INSERT INTO `ai_knowledge_chunk` VALUES (16, 7, 3, 2, '下启用知识库检索 |\n| 检索条数 | 每次对话从知识库检索的片段数量 |\n| 设为默认 | 同时只能有一套默认配置生效 |\n\n## 对话场景（提示词模板）\n\n用户可在对话窗口切换场景，不同场景使用不同系统提示词：\n\n| 场景 ID | 名称 | 适用场景 |\n|---------|------|----------|\n| default | 通用助手 | 日常问答、写作、翻译 |\n| support | 客服问答 | 产品使用、操作指引、FAQ（推荐配合 RAG） |\n| developer | 开发辅助 | 编程、调试、架构（默认使用 deepseek-reasoner） |\n| analyst | 数据分析 | 报表解读、指标分析 |\n\n维护产品 FAQ 后，建议用户选择「客服问答」场景提问。\n\n## 知识库管理\n\n### 新建知识库\n1. 「AI 中心 → 知识库」→ 新增知识库\n2. 填写名称、描述\n3. 可调整：检索条数、分块大小（默认 600 字）、分块重叠（默认 80 字）\n\n### 添加文档\n进入知识库 → 文档管理，两种方式：\n- 上传文件：支持 PDF、DOCX、MD、TXT，单文件不超过 20MB\n- 粘贴文本：直接粘贴标题和正文', '[-0.056911833584308624, -0.03311055898666382, -0.01946932263672352, 0.01482445653527975, -0.060275692492723465, -0.07306618988513947, 0.00858077872544527, 0.04807191714644432, -0.023781713098287582, 0.003129172837361694, 0.0031389514915645123, -0.012624257244169712, 0.005823194980621338, 0.06958498060703278, 0.03606371581554413, -0.04024898633360863, -0.011929971165955068, 0.01961600221693516, 0.006972188130021095, -0.03406887128949165, -0.028983963653445244, 0.03764786198735237, 0.049323588609695435, 0.04271320998668671, 0.07107134163379669, 0.07388759404420853, -0.0760389044880867, -0.05577750504016876, 0.063717782497406, -0.05041879788041115, 0.009852005168795586, -0.06078418344259262, -0.016496608033776283, 0.00242755375802517, 0.021669521927833557, -0.03256295621395111, -0.014795120805501938, -0.009103937074542046, -0.08573933690786362, 0.0006673939060419798, -0.00286514894105494, -0.03166331723332405, 0.04897155612707138, -0.008546553552150726, 0.011646389961242676, -0.02309720776975155, 0.013602123595774174, -0.02739981934428215, 0.05839818716049194, -0.026109036058187485, -0.03942757844924927, -0.02702823095023632, 0.029805371537804604, -0.03226959705352783, -0.028475472703576088, 0.03895820304751396, -0.0637960135936737, -0.023683927953243256, -0.045881498605012894, -0.013220755383372309, -0.07013259083032608, -0.010570737533271313, 0.0021011906210