INSERT INTO `ai_knowledge_chunk` VALUES (17, 7, 3, 3, '添加文档\n进入知识库 → 文档管理，两种方式：\n- 上传文件：支持 PDF、DOCX、MD、TXT，单文件不超过 20MB\n- 粘贴文本：直接粘贴标题和正文\n\n### 索引状态\n| 状态 | 含义 | 处理 |\n|------|------|------|\n| 待索引 | 任务已创建，等待处理 | 稍等刷新 |\n| 索引中 | 正在分块与生成向量 | 稍等，勿重复提交 |\n| 已完成 | 可用于 RAG 检索 | 正常 |\n| 失败 | 索引出错 | 查看错误信息，点「重建索引」 |\n\n文档内容更新后，须点击「重建索引」才会更新向量。\n\n### 文档编写建议\n- 标题具体，如「用户登录与密码重置」\n- FAQ 采用「问：… 答：…」格式，一段一问一答\n- 避免纯图片 PDF（无法提取文字）\n- 用用户会搜索的关键词描述功能\n\n## 会话管理\n\n路径：「AI 中心 → 会话管理」\n- 可查看所有用户的 AI 对话会话列表\n- 可查看某会话的消息历史\n- 可删除违规或测试会话\n需权限：ai:session:query、ai:session:delete\n\n## 用量统计\n\n路径：「AI 中心 → 用量统计」\n查看 AI 调用日志：模型、请求类型（同步/流式）、Token 数、耗时、是否成功。\n用于成本监控与异常排查。\n\n## 限流说明', '[-0.08580335229635239, -0.0058688088320195675, -0.011961469426751137, 0.02487674355506897, -0.05243970826268196, -0.029704155400395393, 0.017411774024367332, 0.047962673008441925, -0.0034064396750181913, -0.026531299576163292, 0.003854143200442195, 0.005742284003645182, 0.02754349820315838, 0.04403066635131836, 0.03626398369669914, -0.010618358850479126, -0.008593960665166378, 0.00605372991412878, -0.006219185888767242, -0.030385442078113556, -0.020769549533724785, 0.02816639095544815, 0.060186922550201416, 0.05551523342728615, 0.04368029162287712, 0.04480928182601929, -0.041694823652505875, -0.053140461444854736, 0.07315085828304291, -0.08642624318599701, 0.03011292777955532, -0.04340777546167374, 0.03809373080730438, 0.010861676186323166, -0.005863942671567202, -0.01922205276787281, -0.02376721613109112, -0.018151458352804184, -0.0737348198890686, 0.0302297193557024, -0.005211852956563234, -0.05606026574969292, 0.015650156885385513, -0.03503766655921936, -0.017110060900449753, 0.012253450229763985, -0.015484701842069626, -0.01229238137602806, -0.003262882586568594, -0.027270983904600143, -0.039203256368637085, -0.005693620536476374, 0.028477836400270466, -0.03521285578608513, 0.025713752955198288, 0.05582668259739876, -0.03863875940442085, -0.020282914862036705, -0.06260062754154205, -0.013285115361213684, -0