INSERT INTO `ai_knowledge_chunk` VALUES (18, 7, 3, 4, 'AI 中心 → 用量统计」\n查看 AI 调用日志：模型、请求类型（同步/流式）、Token 数、耗时、是否成功。\n用于成本监控与异常排查。\n\n## 限流说明\n\n默认每用户每分钟最多 30 次对话请求（发送 + 流式合计），可在 Nacos 配置：\nstarpivot.ai.rate-limit.enabled 与 max-requests-per-minute\n超限提示：「对话请求过于频繁，请稍后再试」\n\n## RAG 高级配置（Nacos，运维）\n\n| 配置项 | 说明 | 建议 |\n|--------|------|------|\n| hyde-enabled | HyDE 查询增强，用假设性回答改善检索 | 可开启 |\n| reranker.enabled | 精排模型二次排序 | 可开启，需 DashScope rerank API |\n| min-vector-score | 向量相似度阈值 | 默认 0.3，召回少时可降到 0.1 测试 |\n| retrieve-top-k | 精排前候选池大小 | 默认 10～20 |\n\n## 权限配置\n\n为用户开通 AI 功能，在「系统管理 → 角色管理」中勾选：\n- AI 中心菜单及子菜单\n- 按钮权限：ai:config:edit、ai:knowledge:edit、ai:session:query 等', '[-0.00478185061365366, -0.041698116809129715, -0.04374139755964279, -0.0017181080766022203, -0.09800191968679428, -0.04302246496081352, 0.030403299257159233, 0.012420513667166231, -0.053314559161663055, 0.038443997502326965, -0.03331686928868294, -0.0155232772231102, 0.02803838811814785, 0.02860596776008606, 0.06144985556602478, -0.026789715513587, 0.03314659744501114, 0.00884476862847805, 0.0009991750121116638, -0.03596556931734085, -0.029343819245696068, 0.05467674881219864, -0.02306261472404003, 0.036438554525375366, 0.01980849727988243, 0.091115303337574, -0.07772044092416763, -0.02209773100912571, 0.11344006657600404, 0.0327114537358284, 0.03626827895641327, -0.05100640654563904, 0.04661713168025017, -0.02480318956077099, 0.002714918227866292, -0.015343544073402882, -0.023478839546442032, -0.011048865504562857, -0.10072629898786543, 0.039579156786203384, 0.0015218204353004694, -0.010661019943654535, 0.006862972397357225, -0.007416361942887306, 0.03426283597946167, -0.01627058908343315, 0.00032665336038917303, -0.04294678941369057, 0.00008683658961672336, 0.01628950797021389, -0.015315165743231772, -0.031349264085292816, -0.014350282028317451, -0.012165104039013386, -0.0009962188778445125, 0.06761754304170609, -0.0012900590663775802, -0.030119510367512703, -0.013309720903635023, 0.01908956468105316, -0.064