INSERT INTO `ai_knowledge_chunk` VALUES (20, 8, 3, 0, '# StarPivot 商城仓储操作手册\n\n商城仓储模块用于管理仓库、商品库存、采购与出入库作业。菜单路径：左侧「商城系统 → 仓库系统」。\n\n## 子模块一览\n\n| 菜单 | 路径 | 用途 |\n|------|------|------|\n| 仓库维护 | 商城 → 仓库系统 → 仓库维护 | 维护仓库基础信息（名称、地址、负责人等） |\n| 地区管理 | 商城 → 仓库系统 → 地区管理 | 维护省市区等地区数据 |\n| 商品库存 | 商城 → 仓库系统 → 商品库存 | 查看各仓库 SKU 库存数量 |\n| 库存工作单 | 商城 → 仓库系统 → 库存工作单 | 处理订单出库、拣货、发货等仓储作业 |\n| 采购需求 | 商城 → 仓库系统 → 采购单维护 → 采购需求 | 登记需采购的商品明细 |\n| 采购单 | 商城 → 仓库系统 → 采购单维护 → 采购单 | 汇总采购需求、提交审批、领取与完成采购 |\n\n## 仓库维护\n\n1. 进入「仓库维护」，点击新增\n2. 填写仓库名称、地址、负责人、联系方式等信息\n3. 保存后可在「商品库存」中选择该仓库查看库存\n\n权限标识：mall:ware:query（查询）、mall:ware:add（新增）、mall:ware:edit（修改）、mall:ware:delete（删除）\n\n## 商品库存', '[-0.04432055354118347, -0.03033353015780449, -0.1076679825782776, 0.02285868301987648, -0.02048032358288765, -0.05341872200369835, 0.026256341487169262, 0.04752945154905319, -0.019951798021793365, -0.0038247238844633102, 0.02799292095005512, 0.014411729760468006, -0.047793712466955185, 0.05239942669868469, 0.03246650472283363, -0.017686692997813225, 0.021820509806275368, 0.042319707572460175, 0.008121345192193985, -0.06070480868220329, -0.04643464833498001, -0.04835999011993408, 0.005535350181162357, 0.07006724178791046, 0.010174095630645752, 0.006526333279907703, -0.01901744306087494, -0.020518075674772263, 0.037109967321157455, -0.03914856165647507, -0.009041544049978256, -0.024670766666531563, -0.0147514957934618, 0.0024161117617040873, -0.010051403194665909, -0.019687537103891373, 0.035505518317222595, 0.021933766081929207, -0.07157731056213379, 0.02595432661473751, -0.0710487887263298, -0.03227774426341057, 0.019026881083846092, 0.0031947416719049215, 0.005587258841842413, -0.01361894328147173, -0.009900395758450031, -0.04013010859489441, -0.04741619527339935, -0.027464397251605988, -0.022783180698752403, -0.011419903486967089, 0.00031056712032295763, -0.04488682746887207, 0.08358237147331238, 0.05202190950512886, 0.0002664742642082274, -0.06319642812013626, -0.02165062725543976, 0.00217662425711751, -0.04560