INSERT INTO `ai_knowledge_chunk` VALUES (22, 8, 3, 2, '「已通过」\n2. 业务状态为「新建」或「已分配」时可领取\n3. 在采购单列表勾选记录，点击「领取采购单」\n4. 领取后状态变为「已领取」，采购人开始执行采购\n\n### 第五步：完成采购\n1. 采购执行完毕后，在详情中完成采购操作\n2. 状态变为「已完成」，库存相应增加\n\n## 采购单状态说明\n\n### 审批状态（audit_status）\n- 草稿：可编辑，可提交审批\n- 审批中：等待审批人处理\n- 已通过：可领取并执行采购\n- 已驳回：需修改后重新提交审批\n- 已撤回：发起人撤回，可修改后再次提交\n\n### 业务状态（status）\n- 新建：刚创建，未分配\n- 已分配：已指定采购人\n- 已领取：采购人已领取，执行中\n- 已完成：采购完成\n- 有异常：执行过程出现异常，需处理\n\n## 库存工作单\n\n库存工作单关联订单出库流程，用于仓库拣货、打包、发货。\n1. 进入「库存工作单」列表\n2. 可按订单号、物流单号、仓库、状态筛选\n3. 打开详情处理对应作业步骤\n4. 完成后订单进入发货状态\n\n## 与审批中心联动\n\n以下仓储/商城业务支持提交审批：\n- 采购单（purchase）\n- 退货单（return）— 在订单模块\n- 优惠券（coupon）— 在营销模块\n- 商品 SPU（spu）— 在商品模块', '[-0.014847456477582456, -0.031192932277917865, -0.05244963616132736, 0.02886057272553444, -0.030661989003419876, -0.007200921885669231, 0.012941748835146427, 0.06962945312261581, -0.04987076669931412, 0.037260860204696655, 0.02685057371854782, 0.03902434930205345, -0.001257435418665409, 0.09784530848264694, 0.006859601009637117, -0.027988309040665627, 0.04387868940830231, -0.030396517366170883, -0.019720759242773056, -0.028177931904792786, -0.03636963292956352, 0.006494577042758465, 0.014913824386894705, 0.04789869114756584, 0.01781505160033703, 0.0012443988816812634, -0.04076887667179108, -0.02434755302965641, 0.03735566884279251, -0.01287538092583418, -0.005039223004132509, -0.03608519956469536, -0.05533190071582794, -0.03035859204828739, 0.002457984024658799, -0.015454249456524847, -0.009552243165671824, -0.00432813772931695, -0.06257548928260803, 0.035838689655065536, -0.04456133395433426, 0.003375283908098936, 0.0138234943151474, -0.06102058291435242, 0.036805763840675354, 0.01114981435239315, -0.018933825194835663, -0.036028310656547546, -0.03092746064066887, -0.01741684414446354, -0.0344923660159111, 0.004193031694740057, 0.045509446412324905, -0.05734190344810486, 0.06432002037763596, 0.09041210263967514, 0.01404156070202589, -0.041982464492321014, -0.028348593041300777, -0.001710159587673843, -0.03119293227791786