INSERT INTO `ai_knowledge_chunk` VALUES (23, 8, 3, 3, '- 采购单（purchase）\n- 退货单（return）— 在订单模块\n- 优惠券（coupon）— 在营销模块\n- 商品 SPU（spu）— 在商品模块\n\n审批通过后，业务单 audit_status 变为 APPROVED，方可继续后续操作（如领取采购单、商品上架）。\n\n## 常见问题\n\n问：为什么不能提交采购审批？\n答：当前审批状态不是草稿/已驳回/已撤回，或采购单无有效明细。\n\n问：审批通过了但无法领取采购单？\n答：须同时满足：审批状态「已通过」且业务状态为「新建」或「已分配」。\n\n问：采购需求如何合并？\n答：勾选多条采购需求，点「合并到采购单」，可新建或并入已有采购单。\n\n问：库存数量不对？\n答：检查采购是否已完成入库、订单出库工作单是否已处理；查看对应业务单据状态。\n\n问：看不到仓库系统菜单？\n答：联系管理员在角色管理中分配商城仓储相关菜单权限。', '[-0.06208163499832153, -0.01271322276443243, -0.033762361854314804, 0.021772345528006554, -0.044382087886333466, -0.03452363237738609, 0.027082210406661034, 0.06014039367437363, -0.016738442704081535, 0.03159273788332939, 0.047122664749622345, 0.03981446474790573, 0.02241942659020424, 0.0751374289393425, 0.003375760279595852, -0.036255523562431335, 0.05503987893462181, -0.04339243844151497, -0.009235166944563389, -0.002581183798611164, -0.042745355516672134, 0.017061982303857803, 0.02413228526711464, 0.004886406939476728, 0.021715249866247177, 0.024341635406017303, -0.06874275207519531, -0.015168321318924429, 0.021030105650424957, -0.012085174210369589, -0.007783994078636169, -0.041298940777778625, -0.01592959277331829, -0.05108127370476723, 0.0035184985026717186, -0.02656835131347179, -0.006413706578314304, -0.013436430133879185, -0.053022511303424835, 0.02380874566733837, -0.047807808965444565, -0.0010818372247740626, 0.002175569301471114, -0.06550735235214233, 0.03621745854616165, -0.0055763088166713715, 0.000005682582013832871, -0.02746284566819668, -0.03380042314529419, 0.010201029479503632, -0.03370526432991028, -0.016329258680343628, 0.05907461419701576, -0.06402287632226944, 0.04346856474876404, 0.06634475290775299, 0.032905932515859604, 0.01513977348804474, -0.00998216401785612, 0.030679214745759964, -0.037264205515384674, -0.005837995558977127, 0.02415131777524948, 0.01677650585770607, -0.029251830652356148, 0.024722270667552948, 0.014920908026397228, -0.04217440262436867, -0.011095521971583366, -0.