INSERT INTO `ai_knowledge_chunk` VALUES (24, 9, 3, 0, '# StarPivot 消息中心使用说明\n\n消息中心是 StarPivot 全平台统一站内信收件箱，用于接收审批通知、业务告警、系统群发等消息。支持顶栏铃铛实时提醒与消息列表管理。\n\n## 入口\n\n### 顶栏铃铛（快捷入口）\n- 登录后页面右上角铃铛图标\n- 显示未读消息角标\n- 点击可预览最近 10 条消息\n- 点击「查看全部」进入完整消息中心\n\n### 消息中心页面\n路径：「系统管理 → 消息中心」\n路由：/system/message/index\n\n## 消息类型\n\n| 类型 | 说明 | 来源 |\n|------|------|------|\n| 审批待办 | 有新的审批任务分配给你 | 审批中心 |\n| 审批结果 | 你发起的审批通过/驳回/撤回 | 审批中心 |\n| 订单消息 | 订单相关业务通知 | 商城订单 |\n| 退款告警 | 退款失败等异常告警 | 商城订单（通知 finance、admin 角色） |\n| 系统通知 | 一般系统级通知 | 各业务模块 |\n| 系统群发 | 管理员手动群发的公告 | 消息中心「群发消息」 |\n\n## 普通用户：查看与已读\n\n1. 进入「系统管理 → 消息中心」，或点击顶栏铃铛\n2. 列表中未读消息行会高亮显示\n3. 可按「已读状态」「消息类型」筛选\n4. 点击某条消息行：自动标记为已读，并跳转到关联业务页（如采购单、待办审批）', '[-0.06586562842130661, -0.009519337676465511, -0.06835994869470596, -0.00956318248063326, -0.013621323741972446, -0.06068212166428566, -0.0004162274126429111, 0.028119556605815887, -0.010815214365720747, 0.0004475891182664782, 0.021435560658574104, 0.020071478560566906, -0.0004475891182664782, 0.03115950897336006, 0.002036378253251314, -0.05125047639012337, 0.07533624768257141, 0.018678167834877968, 0.027086753398180008, -0.02443653903901577, -0.07541419565677643, 0.04633978381752968, -0.007288090419024229, 0.06337130814790726, 0.02001301757991314, 0.06048725172877312, -0.04080551117658615, -0.0446249395608902, 0.04294906556606293, -0.0218642707914114, 0.04419622570276261, -0.05752524733543396, 0.02014942653477192, 0.014956174418330193, -0.016446920111775398, -0.01974020153284073, 0.0056755514815449715, 0.003992373123764992, -0.07498548924922943, -0.0030423880089074373, -0.05401761084794998, -0.021123770624399185, 0.0014140162384137511, -0.02398834004998207, -0.009144214913249016, -0.04602799192070961, 0.02529396116733551, -0.03905169293284416, 0.01309517864137888, 0.0056219627149403095, -0.041273195296525955, 0.009797025471925735, 0.02402731403708458, -0.049886394292116165, 0.03139335289597511, 0.022877588868141174, 0.008954217657446861, -0.03445279225707054, -0.013933113776147366, 0.004