INSERT INTO `ai_knowledge_chunk` VALUES (25, 9, 3, 1, '铃铛\n2. 列表中未读消息行会高亮显示\n3. 可按「已读状态」「消息类型」筛选\n4. 点击某条消息行：自动标记为已读，并跳转到关联业务页（如采购单、待办审批）\n5. 点击「全部已读」一键清空未读角标\n\n### 消息跳转规则\n- 审批待办 → 审批中心待办审批\n- 审批结果 → 审批中心我发起的\n- 采购单相关 → 商城采购单详情\n- 退货单 → 订单退货单\n- 优惠券 → 营销优惠券\n- 商品 → 商品管理\n\n## 管理员：群发消息\n\n需权限：system:message:send（「消息群发」按钮权限）\n超级管理员和 admin 角色默认可用。\n\n操作步骤：\n1. 进入「系统管理 → 消息中心」\n2. 点击「群发消息」\n3. 填写标题、正文\n4. 选择接收用户（可多人）\n5. 发送后，目标用户收件箱和顶栏铃铛会收到「系统群发」类型消息\n\n## 实时推送说明\n\n- 新消息落库后通过 SSE 长连接推送到浏览器\n- 顶栏铃铛未读数会自动更新，无需手动刷新页面\n- 若长时间收不到实时推送：尝试重新登录；检查 starpivot-system 服务与 Redis 是否正常\n\n## 权限配置\n\n| 权限标识 | 说明 |\n|----------|------|\n| system:message:list | 进入消息中心菜单 |', '[-0.08361288905143738, 0.04343269020318985, -0.02859814651310444, -0.01535018440335989, -0.013267794623970984, -0.04343269020318985, 0.023838398978114128, 0.03349671885371208, -0.026852905750274655, 0.009266632609069347, 0.008101485669612885, 0.025226660072803497, -0.007769295480102301, 0.04513826593756676, 0.05711696296930313, -0.041647788137197495, 0.08908659964799881, -0.03143416345119476, 0.01883075013756752, -0.02697190083563328, -0.03153332322835922, 0.05410245805978775, -0.0348849780857563, 0.0384349562227726, 0.0585845522582531, 0.06508953869342804, -0.05477675423026085, -0.03871260955929756, 0.033992525190114975, -0.029589761048555378, 0.037919316440820694, -0.026456261053681377, 0.011671296320855618, 0.01458664145320654, -0.03720535710453987, 0.008056863211095333, 0.004958069883286953, -0.02526632323861122, -0.06941297650337219, -0.0108383409678936, -0.03974388912320137, 0.04012070223689079, 0.034230515360832214, -0.04716116189956665, -0.006157922558486462, -0.0007034261361695826, 0.012464587576687336, -0.02256913296878338, 0.03508330136537552, -0.0035574152134358883, -0.06255100667476654, 0.00948974583297968, 0.03194980323314667, -0.0392877459526062, 0.027725527063012123, 0.03599558770656586, 0.029946742579340935, -0.020585905760526657, -0.022291481494903564, -0.0034012359101325274, -0.03787965327501297,