INSERT INTO `ai_knowledge_chunk` VALUES (26, 9, 3, 2, '## 权限配置\n\n| 权限标识 | 说明 |\n|----------|------|\n| system:message:list | 进入消息中心菜单 |\n| system:message:query | 查询消息列表 |\n| system:message:edit | 标记已读、全部已读 |\n| system:message:send | 群发消息 |\n\n在「系统管理 → 角色管理」中为角色勾选「消息中心」及对应按钮权限，用户重新登录后生效。\n\n## 与其他模块的关系\n\n### 审批中心\n- 待办分配时发送「审批待办」消息\n- 审批完结时向发起人发送「审批结果」消息\n\n### 商城订单\n- 退款失败等异常向 finance、admin 角色发送「退款告警」\n\n### 历史数据迁移\n若从旧版审批通知升级，需执行 sql/patch_migrate_ap_notification_to_sys_user_message.sql 迁移历史通知，并重启相关服务。\n\n## 部署与初始化（管理员）\n\n首次启用消息中心需执行：\nsql/patch_sys_user_message.sql\n然后重启 starpivot-system、starpivot-approval、starpivot-mall-order 及网关，用户重新登录。\n\n## 常见问题', '[-0.03859947994351387, -0.011411771178245544, -0.0630655512213707, 0.02121920883655548, -0.04805358126759529, -0.07188938558101654, 0.05401253327727318, 0.02095182053744793, 0.011411771178245544, -0.014381696470081806, 0.040413904935121536, 0.03724343702197075, -0.0018669465789571404, 0.031131692230701447, -0.00885725300759077, -0.026910770684480667, 0.08380728214979172, 0.010065277107059956, 0.027159059420228004, 0.00785454548895359, -0.05725939571857453, -0.010628703981637956, 0.008083735592663288, 0.03455045074224472, 0.023358318954706192, 0.05924571305513382, -0.037186138331890106, -0.0393061488866806, 0.04690762981772423, -0.013713224790990353, 0.012080242857336998, -0.062492575496435165, 0.023511113598942757, 0.0082986019551754, -0.0026165901217609644, -0.023625709116458893, -0.0015064493054524064, -0.0074343630112707615, -0.08946064114570618, -0.004223310388624668, -0.043240584433078766, -0.03149457648396492, 0.010265818797051908, -0.010886543430387974, 0.012509974651038648, -0.04648744687438011, -0.008121933788061142, -0.048550162464380264, -0.007291119080036879, 0.01557539589703083, -0.04641105234622955, -0.013073401525616646, 0.006078319624066353, -0.020531637594103813, 0.08892586827278137, 0.05126224830746651, 0.0106573523953557, 0.017151080071926117, 0.007926166988909245, 0.027980325743556023, -0.0535