INSERT INTO `ai_knowledge_chunk` VALUES (27, 9, 3, 3, 'starpivot-system、starpivot-approval、starpivot-mall-order 及网关，用户重新登录。\n\n## 常见问题\n\n问：顶栏铃铛没有未读角标，但消息中心有消息？\n答：刷新页面或重新登录，重建 SSE 连接；检查浏览器是否拦截长连接。\n\n问：点击消息没有跳转？\n答：部分旧消息可能缺少业务关联字段；可手动进入对应业务模块查找。\n\n问：收不到审批通知？\n答：确认你是当前步骤的审批人；检查审批服务是否运行；查看消息中心是否已有记录（可能仅推送延迟）。\n\n问：普通用户能否群发消息？\n答：不能，须具备 system:message:send 权限，一般为管理员。\n\n问：消息能删除吗？\n答：当前以已读管理为主，消息记录保留在收件箱供查阅；具体清理策略由系统维护。', '[-0.08484180271625519, 0.01394225750118494, -0.04642137885093689, -0.015546408481895924, -0.003799958154559135, -0.05184776708483696, 0.03032044880092144, 0.042737770825624466, -0.015328560955822468, -0.003851944580674171, 0.045549988746643066, 0.022715581580996513, 0.013397637754678726, 0.029270818457007408, 0.028934143483638763, -0.03665783628821373, 0.10710188001394272, -0.016625745221972466, 0.01091219298541546, -0.013407539576292038, -0.054937247186899185, 0.05703650787472725, 0.004671349190175533, 0.007862323895096779, 0.04018301144242287, 0.06507706642150879, -0.042064424604177475, -0.050778333097696304, 0.03665783628821373, -0.02562681958079338, 0.034439750015735626, -0.039569076150655746, 0.039014555513858795, -0.019180506467819217, -0.0035350751131772995, -0.013457050547003746, 0.0022997793275862932, -0.020774755626916885, -0.07347410917282104, -0.009436769410967829, -0.06468097865581512, 0.02123025432229042, 0.011070627719163896, -0.06052207201719284, 0.011862801387906076, -0.04250011965632439, 0.008857492357492447, -0.02946886233985424, 0.014160105027258396, 0.013259007595479488, -0.03311286121606827, 0.016180148348212242, 0.016397995874285698, -0.04087616130709648, 0.05378859490156174, 0.023685993626713753, 0.058105941861867905, 0.013536267913877964, -0.00938725844025612, 0.0034682354889810085, -0.050421856343746185, -0.008902051486074924, 0.02251753769814968, -0.03853924944996834, -0.010724051855504513, 0.09759579598903656, 0.016120735555887222, -0.009595204144716265, -0.023923644796013832, -0.0027305237017571926, -0.008892149664461613