INSERT INTO `ai_knowledge_document` VALUES (1, 1, '测试文档', 'StarPivot 是一个企业管理系统，包含用户管理、角色权限、审批流程、AI 智能对话等模块。\nAI 助手可以通过知识库检索回答产品相关问题。\n默认管理员账号为 admin。', 'TEXT', NULL, NULL, NULL, NULL, 0, 'PENDING', NULL, 1, NULL, '0', '1', 'admin', '2026-07-06 16:58:25', 'admin', '2026-07-06 16:58:25');
