INSERT INTO `ai_knowledge_document` VALUES (4, 1, 'StarPivot 常见问题', '# StarPivot 常见问题 FAQ\n\n## 登录与账号\n\n问：忘记密码怎么办？\n答：请联系系统管理员在「系统管理 → 用户管理」中重置密码。若环境已对接自助找回流程，可在登录页使用忘记密码功能（以实际部署为准）。\n\n问：登录后左侧菜单很少，很多功能看不到？\n答：这是权限未分配导致。请管理员进入「系统管理 → 角色管理」，编辑你的角色，勾选需要的菜单和按钮权限后保存，然后退出重新登录。\n\n问：提示无权限或 403？\n答：说明当前账号缺少该功能的按钮权限（如 ai:knowledge:edit）。需管理员在角色管理中补充对应权限标识。\n\n问：登录后很快掉线？\n答：Token 可能过期或被踢下线。可在「系统监控 → 在线用户」查看会话；重新登录即可。若频繁掉线，联系管理员检查 Redis 与 JWT 配置。\n\n## 用户与权限管理\n\n问：如何新增一个后台用户？\n答：进入「系统管理 → 用户管理」，点击新增，填写用户名、昵称、部门、岗位，分配角色后保存。\n\n问：如何给用户开通 AI 知识库管理权限？\n答：在「系统管理 → 角色管理」中，为角色勾选「AI 中心」及其子菜单（基础配置、知识库、会话管理等），并勾选对应按钮权限（如 ai:knowledge:edit）。\n\n问：超级管理员和普通管理员有什么区别？\n答：超级管理员通常拥有全部菜单权限；普通角色仅拥有被分配的菜单与按钮权限，遵循最小权限原则。\n\n## 审批中心\n\n问：如何发起审批？\n答：进入「审批中心」，选择对应业务类型的审批模板或入口，填写表单后提交。可在「我发起的」查看进度。\n\n问：审批被驳回了怎么办？\n答：在「我发起的」或待办列表中打开该单据，查看驳回意见，修改内容后重新提交。\n\n问：收不到审批通知？\n答：检查「系统管理 → 消息中心」是否有站内消息；确认审批服务与消息服务正常运行，必要时重新登录刷新消息连接。\n\n## 商城相关\n\n问：商品上架后 C 端看不到？\n答：检查商品审核/上架状态、库存是否充足，以及 C 端商城入口是否正常。B 端在「商城系统 → 商品管理」维护。\n\n问：订单支付失败？\n答：开发环境可能使用支付沙箱，检查支付配置与订单状态；生产环境联系运维确认支付渠道配置。\n\n## 文件中心\n\n问：上传文件失败？\n答：检查文件大小是否超限、当前用户是否有 file:resource 相关权限，以及文件服务（starpivot-file）与 OSS/存储配置是否正常。\n\n## AI 助手与知识库\n\n问：AI 助手在哪里打开？\n答：登录管理端后，点击页面右下角的 AI 对话图标即可打开聊天窗口。\n\n问：AI 能回答公司内部产品问题吗？\n答：可以，需同时满足：① Nacos 中 RAG 已开启；②「AI 中心 → 基础配置」中启用 RAG；③ 知识库中已上传文档且索引状态为「已完成」。否则 AI 仅按通用知识回答。\n\n问：如何在知识库添加文档？\n答：进入「AI 中心 → 知识库」，选择知识库后进入文档管理，可「上传文件」（支持 PDF、DOCX、MD、TXT）或「粘贴文本」。保存后等待索引完成。\n\n问：知识库文档索引一直失败？\n答：常见原因：Embedding API 未配置或地址错误（DashScope 的 base-url 不要带 /v1）、文档为纯图片 PDF 无法解析。可在文档列表点击「重建索引」，并查看后台 IndexService 日志。\n\n问：AI 回答没有引用知识库内容？\n答：确认提问用语与文档内容相关；检查日志是否有 vectorHits > 0；知识库文档是否索引完成且 RAG 双开关均已开启。\n\n问：AI 对话可以选择不同场景吗？\n答：可以。系统支持多种提示词场景（如通用助手、客服问答、开发辅助、数据分析），在对话窗口切换场景后，回答风格会相应调整。\n\n## 系统运维（开发环境参考）\n\n问：服务启动后接口 502 或连不上？\n答：检查网关（8080）、对应微服务是否已注册到 Nacos（8848），以及 MySQL（3307）、Redis（6379）是否已启动。常用命令：docker compose up -d 启动中间件。\n\n问：修改 Nacos 配置后不生效？\n答：部分配置支持热刷新，AI Embedding 等客户端通常需重启对应微服务（如 starpivot-ai）后生效。\n\n问：数据库脚本在哪里？\n答：项目 sql/ 目录，核心库为 star_pivot；商城等业务有独立分库脚本，详见项目 README。', 'TEXT', NULL, NULL, NULL, NULL, 4, 'DONE', NULL, 2, '2026-07-06 18:10:45', '0', '0', 'admin', '2026-07-06 18:10:44', 'admin', '2026-07-06 18:10:45');
INSERT INTO `ai_knowledge_document` VALUES (5, 1, 'StarPivot 产品概览与模块导航', '# StarPivot 星枢后台管理系统 — 产品概览\n\nStarPivot（星枢）是一套企业级微服务管理平台，采用前后端分离架构，管理端为 Vue 3 + Element Plus，API 统一前缀为 /api/v1，默认通过网关端口 8080 访问。\n\n## 主要功能模块\n\n### 系统管理\n路径：左侧菜单「系统管理」\n包含：菜单管理、角色管理、用户管理、部门管理、岗位管理、字典管理、日志管理（操作日志/登录日志）、通知公告、参数配置、消息中心。\n用途：维护组织架构、账号权限、系统参数与站内消息。\n\n### 系统工具\n路径：「系统工具」\n包含：代码生成、外部库代码生成。\n用途：根据数据库表快速生成前后端代码。\n\n### 系统监控\n路径：「系统监控」\n包含：服务器监控、Druid 监控、Redis 缓存、在线用户、定时任务。\n用途：查看运行状态、连接池、缓存与调度任务。\n\n### 文件中心\n路径：「文件中心 → 文件管理」\n用途：统一上传、分类管理与下载业务文件。\n\n### 商城系统\n路径：「商城系统」\n包含：C 端商城、商品管理、仓库系统、订单系统、优惠营销等子模块。\n用途：B 端商品/库存/订单/营销管理，以及 C 端购物前台。\n\n### 审批中心\n路径：「审批中心」\n用途：配置审批模板、发起与处理审批单、查看审批进度与通知。\n\n### 物流管理（TMS）\n路径：「物流管理」\n包含：承运商配置、运单管理、运费规则。\n用途：维护承运商、创建运单、查询物流轨迹与运费。\n\n### AI 中心\n路径：「AI 中心」\n包含：基础配置、会话管理、知识库、用量统计。\n用途：配置 AI 助手、管理对话会话、维护 RAG 知识库文档、查看 AI 调用统计。\n用户可在页面右下角打开 AI 对话窗口进行智能问答。\n\n## 默认登录信息（开发环境）\n默认管理员账号：admin\n默认密码：admin123（若已修改请使用实际密码）\n登录地址：管理前端开发地址一般为 http://localhost:3000\n\n## 权限说明\n用户能看到的菜单由「角色」分配的菜单权限决定。若登录后菜单很少或某功能按钮灰色不可用，需联系管理员在「系统管理 → 角色管理」中为该角色勾选对应菜单与按钮权限。', 'TEXT', NULL, NULL, NULL, NULL, 2, 'DONE', NULL, 2, '2026-07-06 18:11:26', '0', '0', 'admin', '2026-07-06 18:11:26', 'admin', '2026-07-06 18:11:26');
INSERT INTO `ai_knowledge_document` VALUES (6, 3, 'StarPivot 审批中心操作手册', '# StarPivot 审批中心操作手册\n\n审批中心是 StarPivot 的统一审批中台，可与商城采购、退货、优惠券、商品上架等业务联动。菜单路径：左侧「审批中心」。\n\n## 审批中心子菜单\n\n| 菜单 | 路径 | 用途 |\n|------|------|------|\n| 审批模板 | 审批中心 → 审批模板 | 配置审批流程步骤、审批人策略、超时规则 |\n| 业务绑定 | 审批中心 → 业务绑定 | 将业务类型（如采购单）绑定到具体审批模板 |\n| 待办审批 | 审批中心 → 待办审批 | 处理分配给自己的待办，进行通过或驳回 |\n| 我发起的 | 审批中心 → 我发起的 | 查看自己提交的审批进度，可撤回进行中的审批 |\n| 审批统计 | 审批中心 → 审批统计 | 查看审批数据看板与统计 |\n\n## 审批状态说明\n\n### 审批实例状态\n- 审批中：流程正在进行，有待办未处理\n- 已通过：所有审批节点均已通过\n- 已驳回：某一节点审批人驳回，流程结束\n- 已撤回：发起人主动撤回，流程结束\n\n### 业务单 audit_status（以商城为例）\n- DRAFT：草稿，可编辑，可提交审批\n- PENDING：审批中，一般不可直接执行业务后续操作\n- APPROVED：审批已通过，可继续入库、上架、发布等\n- REJECTED：已驳回，需修改后重新提交\n- WITHDRAWN：已撤回，可修改后再次提交\n\n## 管理员：配置审批流程\n\n### 第一步：创建审批模板\n1. 进入「审批中心 → 审批模板」\n2. 点击新增，填写模板名称、编码、说明\n3. 配置审批步骤（可多级），每步指定审批人策略：\n   - DEPT_LEADER：发起人部门负责人\n   - ROLE：指定角色（如 finance 财务角色）\n   - USER：指定具体用户\n4. 保存后点击「发布」，只有已发布模板可被业务使用\n\n### 第二步：业务类型绑定\n1. 进入「审批中心 → 业务绑定」\n2. 为业务类型（如 purchase 采购单、return 退货单、coupon 优惠券、spu 商品）选择对应已发布模板\n3. 保存绑定关系\n\n### 角色与权限\n审批人需具备对应角色。例如默认采购单模板为「部门负责人 → 财务」两关：\n- 第一关：发起人所在部门负责人\n- 第二关：拥有 finance 角色的用户\n在「系统管理 → 角色管理」中为用户分配 finance 等角色后，需重新登录生效。\n\n## 业务用户：发起审批（以采购单为例）\n\n1. 进入「商城系统 → 仓库系统 → 采购单」\n2. 新建或选择 audit_status 为「草稿」的采购单，填写明细并保存\n3. 打开采购单详情，点击「提交审批」\n4. 提交成功后，业务单变为「审批中」，详情页出现审批时间线\n5. 在「审批中心 → 我发起的」可查看进度\n\n其他业务类型提交入口：\n- 退货单：商城 → 订单 → 退货单详情 → 提交审批\n- 优惠券：商城 → 优惠营销 → 优惠券 → 提交审批\n- 商品 SPU：商城 → 商品管理 → 提交审批\n\n## 审批人：处理待办\n\n1. 进入「审批中心 → 待办审批」，切换到「待办」Tab\n2. 找到待处理记录，点击「通过」或「驳回」\n3. 通过：审批意见可选填\n4. 驳回：必须填写审批意见，说明驳回原因\n5. 多级审批时，需按顺序逐关处理；当前关通过后，下一关审批人会在待办中收到任务\n6. 处理完成后可在「已办」Tab 查看历史记录\n\n若待办列表为空：当前登录用户不是该步骤的审批人，需切换有权限的账号或联系管理员调整角色。\n\n## 发起人：撤回审批\n\n1. 仅「审批中」状态的实例可撤回，且仅发起人本人可操作\n2. 进入「审批中心 → 我发起的」\n3. 对进行中的记录点击「撤回」并确认\n4. 撤回后业务单 audit_status 变为 WITHDRAWN，未处理的待办全部取消\n5. 修改业务单后可再次提交审批\n\n## 审批通知\n\n审批任务分配、通过、驳回等事件会发送站内通知。\n查看路径：「系统管理 → 消息中心」，或审批相关页面的通知入口。\n收不到通知时：重新登录刷新连接，并确认 starpivot-approval 服务与消息服务正常运行。\n\n## 常见问题\n\n问：提交审批后业务单一直显示审批中？\n答：说明还有未处理的待办节点。到「待办审批」查看谁有待办，或联系下一关审批人处理。\n\n问：驳回后怎么办？\n答：根据驳回意见修改业务单内容，保存后重新点击「提交审批」。\n\n问：优惠券/商品为什么不能发布或上架？\n答：须先完成审批且状态为 APPROVED。未通过审批时发布/上架会被系统拦截。\n\n问：一人能否测试完整流程？\n答：可以。使用 admin 账号（同时具备部门负责人与 finance 角色），可连续处理两关待办。\n\n问：审批通过后业务单状态未更新？\n答：检查 RabbitMQ 是否开启（MQ_ENABLED=true），对应商城微服务是否正常运行并消费审批完结事件。', 'TEXT', NULL, NULL, NULL, NULL, 5, 'DONE', NULL, 2, '2026-07-06 18:15:57', '0', '0', 'admin', '2026-07-06 18:15:56', 'admin', '2026-07-06 18:15:57');
INSERT INTO `ai_knowledge_document` VALUES (7, 3, 'StarPivot AI 中心管理员指南', '# StarPivot AI 中心管理员指南\n\nAI 中心用于配置智能对话助手、管理知识库（RAG）、查看会话与用量。菜单路径：左侧「AI 中心」。普通用户通过页面右下角 AI 图标打开对话窗口。\n\n## AI 中心子菜单\n\n| 菜单 | 用途 |\n|------|------|\n| 基础配置 | 助手名称、欢迎语、系统提示词、模型、RAG 开关等 |\n| 会话管理 | 管理员查看与删除用户对话会话 |\n| 知识库 | 维护 RAG 文档，上传产品手册、FAQ 等 |\n| 用量统计 | 查看 AI 调用次数、Token 消耗、耗时等 |\n\n## 开启 RAG 知识库问答（必做两步）\n\nRAG 需要同时满足两个开关，缺一不可：\n\n### 开关一：Nacos 基础设施（运维配置）\n在 Nacos 的 starpivot-ai.yaml 中设置：\n- starpivot.ai.rag.enabled: true\n- spring.ai.openai.embedding 配置 DashScope 等 Embedding API\n- embedding 的 base-url 不要带 /v1（Spring AI 会自动追加）\n\n修改后需重启 starpivot-ai 服务。\n\n### 开关二：后台业务开关\n1. 进入「AI 中心 → 基础配置」\n2. 编辑默认配置（或新建并设为默认）\n3. 在「RAG 知识库」区域打开「启用 RAG」\n4. 设置「检索条数」（建议 3～10，默认 5）\n5. 保存\n\n## 基础配置项说明\n\n| 配置项 | 说明 |\n|--------|------|\n| 配置名称 | 如 default，用于区分多套配置 |\n| 助手名称 | 对话窗口显示的名称，支持欢迎语 {botName} 占位符 |\n| 助手头像 | 完整图片 URL，留空用默认头像 |\n| 欢迎语 | 打开新会话时展示的首条消息 |\n| 系统提示词 | 定义 AI 行为边界与回答风格 |\n| 默认模型 | 如 deepseek-chat，需与 Nacos 中配置的模型一致 |\n| 默认温度 | 0～2，越低越稳定，越高越有创造性 |\n| 记忆条数 | 每个会话保留的历史消息条数，默认 30 |\n| 启用 RAG | 是否在本配置下启用知识库检索 |\n| 检索条数 | 每次对话从知识库检索的片段数量 |\n| 设为默认 | 同时只能有一套默认配置生效 |\n\n## 对话场景（提示词模板）\n\n用户可在对话窗口切换场景，不同场景使用不同系统提示词：\n\n| 场景 ID | 名称 | 适用场景 |\n|---------|------|----------|\n| default | 通用助手 | 日常问答、写作、翻译 |\n| support | 客服问答 | 产品使用、操作指引、FAQ（推荐配合 RAG） |\n| developer | 开发辅助 | 编程、调试、架构（默认使用 deepseek-reasoner） |\n| analyst | 数据分析 | 报表解读、指标分析 |\n\n维护产品 FAQ 后，建议用户选择「客服问答」场景提问。\n\n## 知识库管理\n\n### 新建知识库\n1. 「AI 中心 → 知识库」→ 新增知识库\n2. 填写名称、描述\n3. 可调整：检索条数、分块大小（默认 600 字）、分块重叠（默认 80 字）\n\n### 添加文档\n进入知识库 → 文档管理，两种方式：\n- 上传文件：支持 PDF、DOCX、MD、TXT，单文件不超过 20MB\n- 粘贴文本：直接粘贴标题和正文\n\n### 索引状态\n| 状态 | 含义 | 处理 |\n|------|------|------|\n| 待索引 | 任务已创建，等待处理 | 稍等刷新 |\n| 索引中 | 正在分块与生成向量 | 稍等，勿重复提交 |\n| 已完成 | 可用于 RAG 检索 | 正常 |\n| 失败 | 索引出错 | 查看错误信息，点「重建索引」 |\n\n文档内容更新后，须点击「重建索引」才会更新向量。\n\n### 文档编写建议\n- 标题具体，如「用户登录与密码重置」\n- FAQ 采用「问：… 答：…」格式，一段一问一答\n- 避免纯图片 PDF（无法提取文字）\n- 用用户会搜索的关键词描述功能\n\n## 会话管理\n\n路径：「AI 中心 → 会话管理」\n- 可查看所有用户的 AI 对话会话列表\n- 可查看某会话的消息历史\n- 可删除违规或测试会话\n需权限：ai:session:query、ai:session:delete\n\n## 用量统计\n\n路径：「AI 中心 → 用量统计」\n查看 AI 调用日志：模型、请求类型（同步/流式）、Token 数、耗时、是否成功。\n用于成本监控与异常排查。\n\n## 限流说明\n\n默认每用户每分钟最多 30 次对话请求（发送 + 流式合计），可在 Nacos 配置：\nstarpivot.ai.rate-limit.enabled 与 max-requests-per-minute\n超限提示：「对话请求过于频繁，请稍后再试」\n\n## RAG 高级配置（Nacos，运维）\n\n| 配置项 | 说明 | 建议 |\n|--------|------|------|\n| hyde-enabled | HyDE 查询增强，用假设性回答改善检索 | 可开启 |\n| reranker.enabled | 精排模型二次排序 | 可开启，需 DashScope rerank API |\n| min-vector-score | 向量相似度阈值 | 默认 0.3，召回少时可降到 0.1 测试 |\n| retrieve-top-k | 精排前候选池大小 | 默认 10～20 |\n\n## 权限配置\n\n为用户开通 AI 功能，在「系统管理 → 角色管理」中勾选：\n- AI 中心菜单及子菜单\n- 按钮权限：ai:config:edit、ai:knowledge:edit、ai:session:query 等\n修改角色后用户需重新登录。\n\n## 常见问题\n\n问：AI 对话窗口打不开或报错？\n答：检查 starpivot-ai 服务是否启动、Nacos 中 AI_API_KEY 是否配置、网关是否正常。\n\n问：AI 不回答知识库内容？\n答：检查 RAG 双开关、文档索引是否「已完成」、提问是否与文档内容相关。后台日志应有 vectorHits > 0。\n\n问：保存知识库文档提示「正在索引中」？\n答：等待当前索引完成，或点「重建索引」；若长时间卡住，联系管理员清理卡住任务后重试。\n\n问：Embedding 报错 /v1/v1/embeddings？\n答：Nacos 中 embedding base-url 应为 https://dashscope.aliyuncs.com/compatible-mode，末尾不要加 /v1。\n\n问：流式对话日志有 Access Denied？\n答：SSE 异步分发的已知问题，一般不影响对话内容输出；升级版本后通常已修复。\n\n问：如何更换对话模型？\n答：在基础配置中维护「可选模型」列表，用户可在对话窗口下拉切换；也支持按场景绑定不同模型。', 'TEXT', NULL, NULL, NULL, NULL, 6, 'DONE', NULL, 2, '2026-07-06 18:16:32', '0', '0', 'admin', '2026-07-06 18:16:32', 'admin', '2026-07-06 18:16:32');
INSERT INTO `ai_knowledge_document` VALUES (8, 3, 'StarPivot 商城仓储操作手册', '# StarPivot 商城仓储操作手册\n\n商城仓储模块用于管理仓库、商品库存、采购与出入库作业。菜单路径：左侧「商城系统 → 仓库系统」。\n\n## 子模块一览\n\n| 菜单 | 路径 | 用途 |\n|------|------|------|\n| 仓库维护 | 商城 → 仓库系统 → 仓库维护 | 维护仓库基础信息（名称、地址、负责人等） |\n| 地区管理 | 商城 → 仓库系统 → 地区管理 | 维护省市区等地区数据 |\n| 商品库存 | 商城 → 仓库系统 → 商品库存 | 查看各仓库 SKU 库存数量 |\n| 库存工作单 | 商城 → 仓库系统 → 库存工作单 | 处理订单出库、拣货、发货等仓储作业 |\n| 采购需求 | 商城 → 仓库系统 → 采购单维护 → 采购需求 | 登记需采购的商品明细 |\n| 采购单 | 商城 → 仓库系统 → 采购单维护 → 采购单 | 汇总采购需求、提交审批、领取与完成采购 |\n\n## 仓库维护\n\n1. 进入「仓库维护」，点击新增\n2. 填写仓库名称、地址、负责人、联系方式等信息\n3. 保存后可在「商品库存」中选择该仓库查看库存\n\n权限标识：mall:ware:query（查询）、mall:ware:add（新增）、mall:ware:edit（修改）、mall:ware:delete（删除）\n\n## 商品库存\n\n用于查看 SKU 在各仓库的库存数量，支持按仓库、商品筛选。\n库存变动通常由采购入库、订单出库、库存工作单等流程触发，一般不手工改数。\n\n## 采购流程（完整链路）\n\n### 第一步：创建采购需求\n1. 进入「采购需求」\n2. 新增采购需求，选择商品 SKU、数量、目标仓库等\n3. 可多条需求合并到同一采购单\n\n### 第二步：生成采购单\n1. 在采购需求列表勾选记录，点击「合并到采购单」\n2. 可指定已有采购单 ID，或留空自动新建采购单\n3. 进入「采购单」列表查看生成的单据\n\n### 第三步：提交审批\n1. 打开采购单详情（列表点击详情）\n2. 确认明细无误后，点击「提交审批」\n3. 审批状态变为「审批中」，详情页显示审批时间线\n4. 可提交审批的状态：草稿、已驳回、已撤回\n\n默认审批流程为两关：部门负责人 → 财务（finance 角色）。\n审批操作详见《审批中心操作手册》。\n\n### 第四步：审批通过后领取采购单\n1. 审批状态须为「已通过」\n2. 业务状态为「新建」或「已分配」时可领取\n3. 在采购单列表勾选记录，点击「领取采购单」\n4. 领取后状态变为「已领取」，采购人开始执行采购\n\n### 第五步：完成采购\n1. 采购执行完毕后，在详情中完成采购操作\n2. 状态变为「已完成」，库存相应增加\n\n## 采购单状态说明\n\n### 审批状态（audit_status）\n- 草稿：可编辑，可提交审批\n- 审批中：等待审批人处理\n- 已通过：可领取并执行采购\n- 已驳回：需修改后重新提交审批\n- 已撤回：发起人撤回，可修改后再次提交\n\n### 业务状态（status）\n- 新建：刚创建，未分配\n- 已分配：已指定采购人\n- 已领取：采购人已领取，执行中\n- 已完成：采购完成\n- 有异常：执行过程出现异常，需处理\n\n## 库存工作单\n\n库存工作单关联订单出库流程，用于仓库拣货、打包、发货。\n1. 进入「库存工作单」列表\n2. 可按订单号、物流单号、仓库、状态筛选\n3. 打开详情处理对应作业步骤\n4. 完成后订单进入发货状态\n\n## 与审批中心联动\n\n以下仓储/商城业务支持提交审批：\n- 采购单（purchase）\n- 退货单（return）— 在订单模块\n- 优惠券（coupon）— 在营销模块\n- 商品 SPU（spu）— 在商品模块\n\n审批通过后，业务单 audit_status 变为 APPROVED，方可继续后续操作（如领取采购单、商品上架）。\n\n## 常见问题\n\n问：为什么不能提交采购审批？\n答：当前审批状态不是草稿/已驳回/已撤回，或采购单无有效明细。\n\n问：审批通过了但无法领取采购单？\n答：须同时满足：审批状态「已通过」且业务状态为「新建」或「已分配」。\n\n问：采购需求如何合并？\n答：勾选多条采购需求，点「合并到采购单」，可新建或并入已有采购单。\n\n问：库存数量不对？\n答：检查采购是否已完成入库、订单出库工作单是否已处理；查看对应业务单据状态。\n\n问：看不到仓库系统菜单？\n答：联系管理员在角色管理中分配商城仓储相关菜单权限。', 'TEXT', NULL, NULL, NULL, NULL, 4, 'DONE', NULL, 2, '2026-07-06 18:19:20', '0', '0', 'admin', '2026-07-06 18:19:20', 'admin', '2026-07-06 18:19:20');
INSERT INTO `ai_knowledge_document` VALUES (9, 3, 'StarPivot 消息中心使用说明', '# StarPivot 消息中心使用说明\n\n消息中心是 StarPivot 全平台统一站内信收件箱，用于接收审批通知、业务告警、系统群发等消息。支持顶栏铃铛实时提醒与消息列表管理。\n\n## 入口\n\n### 顶栏铃铛（快捷入口）\n- 登录后页面右上角铃铛图标\n- 显示未读消息角标\n- 点击可预览最近 10 条消息\n- 点击「查看全部」进入完整消息中心\n\n### 消息中心页面\n路径：「系统管理 → 消息中心」\n路由：/system/message/index\n\n## 消息类型\n\n| 类型 | 说明 | 来源 |\n|------|------|------|\n| 审批待办 | 有新的审批任务分配给你 | 审批中心 |\n| 审批结果 | 你发起的审批通过/驳回/撤回 | 审批中心 |\n| 订单消息 | 订单相关业务通知 | 商城订单 |\n| 退款告警 | 退款失败等异常告警 | 商城订单（通知 finance、admin 角色） |\n| 系统通知 | 一般系统级通知 | 各业务模块 |\n| 系统群发 | 管理员手动群发的公告 | 消息中心「群发消息」 |\n\n## 普通用户：查看与已读\n\n1. 进入「系统管理 → 消息中心」，或点击顶栏铃铛\n2. 列表中未读消息行会高亮显示\n3. 可按「已读状态」「消息类型」筛选\n4. 点击某条消息行：自动标记为已读，并跳转到关联业务页（如采购单、待办审批）\n5. 点击「全部已读」一键清空未读角标\n\n### 消息跳转规则\n- 审批待办 → 审批中心待办审批\n- 审批结果 → 审批中心我发起的\n- 采购单相关 → 商城采购单详情\n- 退货单 → 订单退货单\n- 优惠券 → 营销优惠券\n- 商品 → 商品管理\n\n## 管理员：群发消息\n\n需权限：system:message:send（「消息群发」按钮权限）\n超级管理员和 admin 角色默认可用。\n\n操作步骤：\n1. 进入「系统管理 → 消息中心」\n2. 点击「群发消息」\n3. 填写标题、正文\n4. 选择接收用户（可多人）\n5. 发送后，目标用户收件箱和顶栏铃铛会收到「系统群发」类型消息\n\n## 实时推送说明\n\n- 新消息落库后通过 SSE 长连接推送到浏览器\n- 顶栏铃铛未读数会自动更新，无需手动刷新页面\n- 若长时间收不到实时推送：尝试重新登录；检查 starpivot-system 服务与 Redis 是否正常\n\n## 权限配置\n\n| 权限标识 | 说明 |\n|----------|------|\n| system:message:list | 进入消息中心菜单 |\n| system:message:query | 查询消息列表 |\n| system:message:edit | 标记已读、全部已读 |\n| system:message:send | 群发消息 |\n\n在「系统管理 → 角色管理」中为角色勾选「消息中心」及对应按钮权限，用户重新登录后生效。\n\n## 与其他模块的关系\n\n### 审批中心\n- 待办分配时发送「审批待办」消息\n- 审批完结时向发起人发送「审批结果」消息\n\n### 商城订单\n- 退款失败等异常向 finance、admin 角色发送「退款告警」\n\n### 历史数据迁移\n若从旧版审批通知升级，需执行 sql/patch_migrate_ap_notification_to_sys_user_message.sql 迁移历史通知，并重启相关服务。\n\n## 部署与初始化（管理员）\n\n首次启用消息中心需执行：\nsql/patch_sys_user_message.sql\n然后重启 starpivot-system、starpivot-approval、starpivot-mall-order 及网关，用户重新登录。\n\n## 常见问题\n\n问：顶栏铃铛没有未读角标，但消息中心有消息？\n答：刷新页面或重新登录，重建 SSE 连接；检查浏览器是否拦截长连接。\n\n问：点击消息没有跳转？\n答：部分旧消息可能缺少业务关联字段；可手动进入对应业务模块查找。\n\n问：收不到审批通知？\n答：确认你是当前步骤的审批人；检查审批服务是否运行；查看消息中心是否已有记录（可能仅推送延迟）。\n\n问：普通用户能否群发消息？\n答：不能，须具备 system:message:send 权限，一般为管理员。\n\n问：消息能删除吗？\n答：当前以已读管理为主，消息记录保留在收件箱供查阅；具体清理策略由系统维护。', 'TEXT', NULL, NULL, NULL, NULL, 4, 'DONE', NULL, 2, '2026-07-06 18:19:42', '0', '0', 'admin', '2026-07-06 18:19:42', 'admin', '2026-07-06 18:19:42');
